// Full-screen auth/marketing routes — the side nav stays hidden on these.
const SIDE_NAV_HIDDEN_ROUTES = new Set([
  'splash', 'signin', 'signup', 'forgot', 'resethash', 'verf-link', 'accept-invite', 'signout'
]);

// Route path ('/analytics/conversions') -> { sectionToken, childToken, children }
// for left-nav active state + the contextual top sub-nav.
let sideNavRouteIndex = {};
// sub-nav child token -> route, for navigating from a sub-nav tap.
let subNavRouteByToken = {};
let currentRouteName = null;

// Persona badge shown in the nav footer, keyed by uiMode.
const PERSONA_BADGE = {
  admin:      { caption: 'Platform Admin', icon: 'shield_person' },
  reseller:   { caption: 'Reseller',       icon: 'handshake' },
  managed:    { caption: 'Managed',        icon: 'visibility' },
  self_serve: { caption: 'Self-Serve',     icon: 'rocket_launch' },
};

/** Render the side nav from the current AuthController scope (capabilities + uiMode + orgs). */
function renderSideNavFromScope() {
  const nav = document.getElementById('m5t-side-nav');
  if (!nav) return;

  // Cold sign-in: authenticated but /me not back yet → show a skeleton instead of
  // the ungated (Settings-only) tree, which would otherwise flash. Returning users
  // have cached scope and paint the real tree immediately.
  const loading = !AuthController.getScope() && AuthController.isAuthenticated();

  const caps = AuthController.getCapabilities();
  const uiMode = AuthController.getUiMode();
  const tree = NavMetaManager.getSideNav(caps, { uiMode });

  // Rebuild the route index (section + children) and the child route map.
  sideNavRouteIndex = {};
  subNavRouteByToken = {};
  const indexItem = (item) => {
    if (!item.route) return;
    sideNavRouteIndex[item.route] = { sectionToken: item.token, childToken: null, children: item.children || null };
    if (Array.isArray(item.children)) {
      item.children.forEach((c) => {
        if (!c.route) return;
        subNavRouteByToken[c.token] = c.route;
        // A child route resolves to its parent section (left active) + itself (sub active).
        // A shared parent/child route (e.g. /analytics == Overview) makes the first child active.
        sideNavRouteIndex[c.route] = { sectionToken: item.token, childToken: c.token, children: item.children };
      });
    }
  };
  const walk = (nodes) => nodes.forEach((n) => {
    if (n.group && Array.isArray(n.items)) walk(n.items);
    else indexItem(n);
  });
  walk(tree);

  const memberships = AuthController.getMemberships();
  const activeOrg = AuthController.getActiveOrg();

  // One batched render: nav tree + org switcher + persona badge.
  nav.setState({
    buttons: tree,
    orgs: memberships.map((m) => ({ guid: m.orgGuid, name: m.name || m.channel, channel: m.channel })),
    activeOrg: activeOrg?.guid || null,
    footerBadge: PERSONA_BADGE[uiMode] || null,
    loading,
  });

  // Re-apply active section + sub-nav for the current route (setState re-rendered the tree).
  if (currentRouteName) applyActiveForRoute(currentRouteName);
}

/** Set the active left-nav section + feed/show the contextual top sub-nav for a route. */
function applyActiveForRoute(routeName) {
  const nav = document.getElementById('m5t-side-nav');
  const entry = sideNavRouteIndex[`/${routeName}`] || sideNavRouteIndex[routeName] || null;
  nav?.setActiveToken(entry?.sectionToken || null);
  updateSubNav(entry);
}

/** Contextual top sub-nav: shown only when the active section has >1 sub-item. */
function updateSubNav(entry) {
  const sub = document.getElementById('m5t-sub-nav');
  const shell = document.getElementById('app-shell');
  if (!sub) return;
  const children = entry?.children;
  // Always reserve the sub-nav slot on content routes so switching between sections
  // (some with tabs, some without) never shifts the content below. No tabs → empty
  // spacer (invisible, same height); tabs → the contextual sub-nav.
  sub.hidden = false;
  if (children && children.length > 1) {
    sub.updateButtons(children.map((c) => ({
      token: c.token, caption: c.caption, enabled: true, selected: c.token === entry.childToken,
    })));
    shell?.classList.add('has-sub-nav');
  } else {
    sub.updateButtons([]); // invisible spacer — reserves the bar's height
    shell?.classList.remove('has-sub-nav');
  }
}

/** Cycle to the next available UI language. */
function cycleLanguage() {
  const langs = (I18nController.getAvailableLanguages && I18nController.getAvailableLanguages()) || [];
  if (langs.length < 2) {
    PubSub.publish(AppBroadcast.UI_TOAST, { message: 'Only one language is available', type: 'info' });
    return;
  }
  const current = localStorage.getItem(FEATURE_FLAGS.FF_SSE_LS_USER_LANG) || FEATURE_FLAGS.FF_SSE_I18N_LANG || langs[0];
  const next = langs[(langs.indexOf(current) + 1) % langs.length];
  I18nController.setLanguage(next);
  PubSub.publish(AppBroadcast.UI_TOAST, { message: `Language: ${next}`, type: 'info' });
}

/** Feed + wire the side nav once, then keep it in sync with scope. Runs before router.resolve(). */
function setupSideNav() {
  const nav = document.getElementById('m5t-side-nav');
  if (!nav) return;
  NavMetaManager.setAppToken('client-saas');

  // Sync the shell's collapsed class with the nav's RESTORED collapse state (from
  // localStorage). The component restores data-collapsed on connect without firing
  // nav-collapse, so without this the content uses the expanded margin against a
  // collapsed rail on first paint (a big gap) until the user toggles the menu.
  document.getElementById('app-shell')?.classList.toggle(
    'nav-collapsed', nav.getAttribute('data-collapsed') === 'true'
  );

  // Component emits composed CustomEvents; route everything through the router/controllers.
  nav.addEventListener('nav-select', (e) => {
    const route = e.detail?.route;
    if (route) router.navigate(route.startsWith('/') ? route : `/${route}`);
  });
  nav.addEventListener('logo-click', () => router.navigate('/home'));
  nav.addEventListener('nav-collapse', (e) => {
    document.getElementById('app-shell')?.classList.toggle('nav-collapsed', !!e.detail?.collapsed);
  });
  nav.addEventListener('org-switch', (e) => {
    const guid = e.detail?.orgGuid;
    if (guid) AuthController.setActiveOrg(guid); // refetch /me → AUTH.SCOPE.LOADED → re-render
  });
  nav.addEventListener('footer-action', (e) => {
    switch (e.detail?.action) {
      case 'account': router.navigate('/settings'); break;
      case 'signout': router.navigate('/signout'); break;
      case 'lang':    cycleLanguage(); break;
    }
  });

  // Contextual top sub-nav (m5t-primary-nav reused): tap a sub-item → navigate to its route.
  const sub = document.getElementById('m5t-sub-nav');
  sub?.addEventListener('nav-select', (e) => {
    const route = subNavRouteByToken[e.detail?.token];
    if (route) router.navigate(route);
  });

  // Re-resolve nav i18n captions on language change (I18nController fires this).
  document.addEventListener('language-changed', () => renderSideNavFromScope());

  // Initial render from cached/empty scope; re-render whenever scope resolves/changes.
  renderSideNavFromScope();
  PubSub.subscribe(AppBroadcast.AUTH_SCOPE_LOADED, () => renderSideNavFromScope());
}

/** Show/hide the nav per route and sync the active item (route is source of truth). */
function updateSideNavForRoute(routeName) {
  currentRouteName = routeName;
  const nav = document.getElementById('m5t-side-nav');
  const shell = document.getElementById('app-shell');
  if (!nav || !shell) return;

  const showNav = !SIDE_NAV_HIDDEN_ROUTES.has(routeName);
  nav.hidden = !showNav;
  shell.classList.toggle('has-side-nav', showNav);

  if (showNav) {
    applyActiveForRoute(routeName);
  } else {
    // Auth/splash routes: hide the contextual sub-nav too.
    const sub = document.getElementById('m5t-sub-nav');
    if (sub) sub.hidden = true;
    shell.classList.remove('has-sub-nav');
  }
}

// Route is the single source of truth for nav visibility + active item.
PubSub.subscribe(AppBroadcast.ROUTE_NAV_AFTER, (_msg, data) => {
  if (data?.route) updateSideNavForRoute(data.route);
});

