// Splash is the ONLY unauth landing mvvLegit allows in every auth state (incl. the
// brand-new state 0 of a cold incognito load), so it's where invite links are funneled.
// The invite params ride in the real query string (?uid=&token=), which survives the
// bounce — render the accept-invite (set-password) form when they're present.
const loadSplash = () => {
  console.log('[Router] Route: splash');
  PubSub.publish(AppBroadcast.ROUTE_NAV_BEFORE, { route: 'splash' });
  const inviteParams = new URLSearchParams(window.location.search || '');
  const isInvite = !!(inviteParams.get('uid') && inviteParams.get('token'));
  // Use LITERAL import() strings in each branch — a computed import(variable) is not
  // statically analyzable by Vite, so the chunk is never emitted/deployed (→ 404 at runtime).
  const loader = isInvite
    ? import('./routes/accept-invite-route.js')
    : import('./routes/splash-route.js');
  loader
    .then(module => {
      const container = document.getElementById('app');
      container.innerHTML = module.render();
      if (module.init) module.init();
      PubSub.publish(AppBroadcast.ROUTE_NAV_AFTER, { route: 'splash' });
    })
    .catch(err => {
      console.error('[Router] Error loading splash route:', err);
      PubSub.publish(AppBroadcast.ROUTE_NAV_ERROR, { route: 'splash', error: err });
    });
};
router.on('/', loadSplash);
router.on('/splash', loadSplash);

