// ============================================
// Section Routes (persona-aware side-nav destinations)
// ============================================
// All sections require the same auth level as /home, so we gate them behind the
// known-good 'home' route token — mvvLegit's allow-list is CDN-configured and does
// not know per-section tokens. Capability/persona VISIBILITY is enforced in the nav
// (Step 5) and on the server (row-level scope); this guard is just authn.
const SECTION_ROUTES = [
  // NOTE: /magnets has a dedicated handler below (real view), so it is intentionally NOT
  // in this placeholder list — same reason /clients and /team aren't.
  { path: '/templates',     name: 'templates',     title: 'Templates',     icon: 'content_copy' },
  { path: '/conversations', name: 'conversations', title: 'Conversations', icon: 'forum' },
  { path: '/ab-testing',    name: 'ab-testing',    title: 'A/B Testing',   icon: 'science' },
  { path: '/analytics',     name: 'analytics',     title: 'Analytics',     icon: 'monitoring' },
  { path: '/ad-accounts',   name: 'ad-accounts',   title: 'Ad Accounts',   icon: 'ads_click' },
  // NOTE: /clients and /team have dedicated handlers below (real views), so they are
  // intentionally NOT in this placeholder list.
  { path: '/billing',       name: 'billing',       title: 'Billing',       icon: 'receipt_long' },
  { path: '/settings',      name: 'settings',      title: 'Settings',      icon: 'settings' },
  // Sub-nav children (parent routes above cover Overview/General/All which share the parent path)
  { path: '/magnets/drafts',          name: 'magnets/drafts',          title: 'Magnets · Drafts',        icon: 'widgets' },
  { path: '/magnets/archived',        name: 'magnets/archived',        title: 'Magnets · Archived',      icon: 'widgets' },
  { path: '/analytics/conversions',   name: 'analytics/conversions',   title: 'Analytics · Conversions', icon: 'monitoring' },
  // NOTE: /analytics/ad-performance has a dedicated handler below (real view), so it is
  // intentionally NOT in this placeholder list.
  { path: '/settings/workspace',      name: 'settings/workspace',      title: 'Settings · Workspace',    icon: 'settings' },
  { path: '/settings/integrations',   name: 'settings/integrations',   title: 'Settings · Integrations', icon: 'settings' },
  { path: '/settings/security',       name: 'settings/security',       title: 'Settings · Security',     icon: 'settings' },
];

SECTION_ROUTES.forEach(({ path, name, title, icon }) => {
  router.on(path, () => {
    console.log(`[Router] Route: ${path}`);
    if (!checkRouteAccess('home')) {
      navigateToRoute('signin');
      return;
    }
    PubSub.publish(AppBroadcast.ROUTE_NAV_BEFORE, { route: name });
    import('./routes/section-route.js')
      .then((module) => {
        const container = document.getElementById('app');
        container.innerHTML = module.render({ title, icon, name });
        if (module.init) module.init({ name });
        PubSub.publish(AppBroadcast.ROUTE_NAV_AFTER, { route: name });
      })
      .catch((err) => {
        console.error(`[Router] Error loading section route (${name}):`, err);
        PubSub.publish(AppBroadcast.ROUTE_NAV_ERROR, { route: name, error: err });
      });
  });
});

