// (manage_team) visibility is enforced by the nav + the server.
router.on('/team', () => {
  console.log('[Router] Route: /team');
  if (!checkRouteAccess('home')) {
    navigateToRoute('signin');
    return;
  }
  PubSub.publish(AppBroadcast.ROUTE_NAV_BEFORE, { route: 'team' });
  import('./routes/team-route.js')
    .then((module) => {
      const container = document.getElementById('app');
      container.innerHTML = module.render();
      if (module.init) module.init();
      PubSub.publish(AppBroadcast.ROUTE_NAV_AFTER, { route: 'team' });
    })
    .catch((err) => {
      console.error('[Router] Error loading team route:', err);
      PubSub.publish(AppBroadcast.ROUTE_NAV_ERROR, { route: 'team', error: err });
    });
});

