/**
 * dashboard-route.js — client-saas /home
 *
 * Translation of the MachFiveMagnet demo dashboard (demo/index.html .demo-content)
 * into our shell: dark side-nav + light content. Built entirely from the tokenized
 * primitive kit (styles/dashboard-kit.css) — no inline styles, no demo --m5-* vars.
 *
 * Data posture (verified): "Active Magnets" (GET /m5t/v5/sseEtherSubscriberApp) and
 * "Leads Captured" + Recent Leads (GET /m5t/v5/m5mLead) are live + owner-scoped by the
 * JWT. Conversations / Flow Completion / the charts have NO owner-scoped stat model yet,
 * so they render as honest empty-states, not fabricated numbers — filling in as those
 * endpoints are added.
 */

import AuthController from '../services/AuthController.js';

const emptyState = (icon, msg) =>
  `<div class="m5t-empty"><span class="material-symbols-outlined" aria-hidden="true">${icon}</span><p>${msg}</p></div>`;

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
const leadName = (l) => [l.first_name, l.last_name].filter(Boolean).join(' ').trim() || l.email || '(no name)';
const leadInitials = (l) => ((leadName(l).split(/\s+/).slice(0, 2).map((w) => w[0] || '').join('')) || '?').toUpperCase();
function leadWhen(l) {
  const tz = l.created?.created_tz;
  if (!tz) return '';
  try { return new Date(tz).toLocaleDateString([], { month: 'short', day: 'numeric' }); } catch { return ''; }
}

let stylesInjected = false;
function ensureStyles() {
  if (stylesInjected) return;
  const s = document.createElement('style');
  s.id = 'm5t-dash-recent-styles';
  s.textContent = `
    .page-shell .recent-lead { display:flex; align-items:center; gap:10px; padding:10px 4px; border-bottom:1px solid var(--color-surface-2,#EAF0F7); text-decoration:none; color:inherit; }
    .page-shell .recent-lead:last-child { border-bottom:0; }
    .page-shell .recent-lead:hover { background:var(--color-surface,#F7FAFD); }
    .page-shell .recent-lead__ava { flex:0 0 auto; width:34px; height:34px; border-radius:50%; display:grid; place-items:center; font-weight:700; font-size:0.74rem; color:#fff; background:var(--color-primary-600,#0072BA); }
    .page-shell .recent-lead__main { flex:1 1 auto; min-width:0; display:flex; flex-direction:column; }
    .page-shell .recent-lead__name { font-weight:600; font-size:0.9rem; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
    .page-shell .recent-lead__sub { font-size:0.78rem; color:var(--color-text-subtle,#6C7C9A); overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
    .page-shell .recent-lead__badge { flex:0 0 auto; font-size:0.64rem; font-weight:700; letter-spacing:0.03em; padding:3px 8px; border-radius:999px; background:var(--color-surface-2,#EAF0F7); color:var(--color-text-muted,#4A5A78); }
    .page-shell .recent-lead__badge[data-s="NEW"] { background:#DBEAFE; color:#1D4ED8; }
    .page-shell .recent-lead__badge[data-s="WORKING"] { background:#FEF3C7; color:#92400E; }
    .page-shell .recent-lead__badge[data-s="QUALIFIED"], .page-shell .recent-lead__badge[data-s="CONVERTED"] { background:#DCFCE7; color:#047857; }
    .page-shell .recent-lead__time { flex:0 0 auto; font-size:0.74rem; color:var(--color-text-subtle,#6C7C9A); }
  `;
  document.head.appendChild(s);
  stylesInjected = true;
}

function recentLeadHTML(l) {
  return `<a class="recent-lead" href="#/leads">
    <span class="recent-lead__ava">${esc(leadInitials(l))}</span>
    <span class="recent-lead__main">
      <span class="recent-lead__name">${esc(leadName(l))}</span>
      <span class="recent-lead__sub">${esc(l.email || l.phone || '')}</span>
    </span>
    <span class="recent-lead__badge" data-s="${esc(l.status)}">${esc(l.status)}</span>
    <span class="recent-lead__time">${esc(leadWhen(l))}</span>
  </a>`;
}

const statCard = ({ icon, label, valueId, value = '—', subId, sub = '' }) => `
  <div class="stat-card">
    <div class="stat-header">
      <span class="material-symbols-outlined stat-icon" aria-hidden="true">${icon}</span>
      <span class="stat-label">${label}</span>
    </div>
    <div class="stat-value"${valueId ? ` id="${valueId}"` : ''}>${value}</div>
    <div class="stat-change"><span class="stat-sublabel"${subId ? ` id="${subId}"` : ''}>${sub}</span></div>
  </div>`;

const chartCard = (icon, title, { wide = false, full = false, controls = false } = {}) => `
  <div class="dashboard-card${wide ? ' chart-card-wide' : ''}${full ? ' chart-card-full' : ''}">
    <div class="card-header">
      <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">${icon}</span> ${title}</h2>
      ${controls ? `<div class="chart-controls">
        <button class="chart-period-btn active" type="button" data-period="7">7 Days</button>
        <button class="chart-period-btn" type="button" data-period="30">30 Days</button>
      </div>` : ''}
    </div>
    <div class="card-body">${emptyState('insights', 'Insights appear here once your magnets start capturing conversations.')}</div>
  </div>`;

export function render() {
  ensureStyles();
  return `
    <div class="page-shell" data-section="home">
      <div class="page-header">
        <div class="page-header-text">
          <h1 class="page-title">Dashboard</h1>
          <p class="page-description">Your magnets, conversations, and lead performance at a glance.</p>
        </div>
        <a class="btn btn-primary" href="#/magnets">
          <span class="material-symbols-outlined" aria-hidden="true">add</span>
          New Magnet
        </a>
      </div>

      <div class="stats-grid">
        ${statCard({ icon: 'widgets', label: 'Active Magnets', valueId: 'stat-active-magnets', subId: 'stat-active-magnets-sub', sub: 'Loading…' })}
        ${statCard({ icon: 'forum', label: 'Conversations Started', sub: 'Coming soon' })}
        ${statCard({ icon: 'person_add', label: 'Leads Captured', valueId: 'stat-leads', subId: 'stat-leads-sub', sub: 'Loading…' })}
        ${statCard({ icon: 'check_circle', label: 'Flow Completion Rate', sub: 'Coming soon' })}
      </div>

      <div class="charts-section">
        ${chartCard('show_chart', 'Conversation Trends', { wide: true, controls: true })}
        <div class="charts-grid">
          ${chartCard('filter_alt', 'Completion Funnel')}
          ${chartCard('source', 'Traffic Sources')}
          ${chartCard('bar_chart', 'Magnet Performance', { full: true })}
        </div>
      </div>

      <div class="content-grid">
        <div class="dashboard-card">
          <div class="card-header">
            <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">bolt</span> Recent Interactions</h2>
            <span class="live-indicator"><span class="pulse-dot"></span> Live</span>
          </div>
          <div class="card-body">
            ${emptyState('sensors', "No interactions yet — they'll stream in live as visitors engage your magnets.")}
          </div>
        </div>
        <div class="dashboard-card">
          <div class="card-header">
            <h2 class="card-title"><span class="material-symbols-outlined" aria-hidden="true">group</span> Recent Leads</h2>
            <a class="view-all-link" href="#/leads">View all →</a>
          </div>
          <div class="card-body" id="recent-leads-body">
            ${emptyState('hourglass_empty', 'Loading leads…')}
          </div>
        </div>
      </div>
    </div>`;
}

/**
 * Progressive enhancement: fill the one genuinely-live KPI (Active Magnets) from the
 * owner-scoped magnets endpoint. Any failure degrades to an em-dash — never a crash,
 * never a fabricated/cross-tenant number.
 */
export async function init() {
  const base = AuthController.getConfig?.().BASE_URL || '';
  await Promise.all([loadActiveMagnets(base), loadLeads(base)]);
}

async function loadActiveMagnets(base) {
  const valueEl = document.getElementById('stat-active-magnets');
  const subEl = document.getElementById('stat-active-magnets-sub');
  if (!valueEl) return;

  try {
    const res = await fetch(`${base}/m5t/v5/sseEtherSubscriberApp`); // mvvLegit injects the Bearer
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const json = await res.json();
    const magnets = Array.isArray(json?.data) ? json.data : [];

    const active = magnets.filter((m) => m.status === 'ENABLED').length;
    valueEl.textContent = String(active);

    // "Across N domains" — distinct active hostnames across app_domains JSONB (shape-tolerant).
    const domains = new Set();
    magnets.forEach((m) => {
      const list = Array.isArray(m.app_domains) ? m.app_domains : [];
      list.forEach((d) => {
        const host = typeof d === 'string' ? d : (d && (d.domain || d.host));
        if (host && (typeof d === 'string' || d.active !== false)) domains.add(String(host).toLowerCase());
      });
    });
    if (subEl) {
      subEl.textContent = domains.size
        ? `Across ${domains.size} domain${domains.size === 1 ? '' : 's'}`
        : (active ? 'No domains configured' : 'No magnets yet');
    }
  } catch (err) {
    console.warn('[dashboard] Active Magnets fetch failed:', err);
    valueEl.textContent = '—';
    if (subEl) subEl.textContent = 'Unavailable';
  }
}

// Leads Captured KPI + Recent Leads list — owner-scoped m5mLead (API orders id DESC = recent first).
async function loadLeads(base) {
  const statEl = document.getElementById('stat-leads');
  const statSub = document.getElementById('stat-leads-sub');
  const listEl = document.getElementById('recent-leads-body');
  try {
    const res = await fetch(`${base}/m5t/v5/m5mLead`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const json = await res.json();
    const leads = (Array.isArray(json?.data) ? json.data : []).filter((l) => !['DELETED', 'ARCHIVED'].includes(l.status));
    const newCount = leads.filter((l) => l.status === 'NEW').length;

    if (statEl) statEl.textContent = String(leads.length);
    if (statSub) statSub.textContent = leads.length ? `${newCount} new to work` : 'No leads yet';
    if (listEl) {
      listEl.innerHTML = leads.length
        ? leads.slice(0, 5).map(recentLeadHTML).join('')
        : emptyState('contacts', 'No leads captured yet. Publish a magnet to start collecting.');
    }
  } catch (err) {
    console.warn('[dashboard] Leads fetch failed:', err);
    if (statEl) statEl.textContent = '—';
    if (statSub) statSub.textContent = 'Unavailable';
    if (listEl) listEl.innerHTML = emptyState('error', 'Could not load recent leads.');
  }
}

export default { render, init };
