/**
 * leads-route.js — client-saas /leads
 *
 * The payoff of the magnet loop: the leads your magnets captured. Tenant-scoped server-side
 * (m5mLead → listRecordsByOwner(ownerGuids)), so each org sees only its own; resellers see their
 * subtree; managed clients see their own (read-only is fine — viewing only). Lists leads with a
 * status filter, inline status change (PUT /m5t/v5/m5mLead/:id), a detail drawer, and CSV export.
 * Each lead is linked to the magnet that captured it (magnet_guid → /magnets name map).
 */

import AuthController from '../services/AuthController.js';
import PubSub from 'pubsub-js';
import AppBroadcast from '../../../../shared/appBroadcast.js';

let stylesInjected = false;
const state = { leads: [], magnetNames: {}, filter: 'ALL', canManage: false };

const STATUSES = ['NEW', 'WORKING', 'QUALIFIED', 'UNQUALIFIED', 'CONVERTED', 'EXPORTED'];
const ESC = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };
const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ESC[c]);
const toast = (message, type = 'info') => { try { PubSub.publish(AppBroadcast.UI_TOAST, { message, type }); } catch { /* no-op */ } };
const apiBase = () => AuthController.getConfig?.().BASE_URL || '';
const fullName = (l) => [l.first_name, l.last_name].filter(Boolean).join(' ').trim() || l.email || '(no name)';
const initials = (l) => (fullName(l).split(/\s+/).slice(0, 2).map((w) => w[0] || '').join('') || '?').toUpperCase();
function when(l) {
  const tz = l.created?.created_tz;
  if (!tz) return '';
  try { return new Date(tz).toLocaleDateString([], { month: 'short', day: 'numeric', year: 'numeric' }); } catch { return ''; }
}

