function emptyState(icon, msg) {
  return `<div class="m5t-empty"><span class="material-symbols-outlined" aria-hidden="true">${icon}</span><p>${msg}</p></div>`;
}

function statusSelect(l) {
  return `<select class="leads-status" data-id="${esc(l.id)}" data-act="status" onclick="event.stopPropagation()">
    ${STATUSES.map((s) => `<option value="${s}" ${l.status === s ? 'selected' : ''}>${s[0]}${s.slice(1).toLowerCase()}</option>`).join('')}
  </select>`;
}

function rowHTML(l) {
  const magnet = state.magnetNames[l.magnet_guid] || (l.lead_source || '—');
  return `
    <tr class="leads-row" data-id="${esc(l.id)}">
      <td>
        <span class="leads-who">
          <span class="leads-avatar">${esc(initials(l))}</span>
          <span><span class="leads-name">${esc(fullName(l))}</span>${l.company ? `<div class="leads-sub">${esc(l.company)}</div>` : ''}</span>
        </span>
      </td>
      <td>${l.email ? esc(l.email) : '<span class="leads-muted">—</span>'}${l.phone ? `<div class="leads-sub">${esc(l.phone)}</div>` : ''}</td>
      <td>${l.product_interest ? esc(l.product_interest) : '<span class="leads-muted">—</span>'}</td>
      <td><span class="leads-sub">${esc(magnet)}</span>${(l.utm_campaign || l.utm_source) ? `<div class="leads-sub" title="Campaign / source">${esc(l.utm_campaign || l.utm_source)}${l.gclid ? ' <span class="leads-badge" data-s="QUALIFIED" style="font-size:0.58rem;padding:1px 6px">Ads</span>' : ''}</div>` : ''}</td>
      <td>${state.canManage ? statusSelect(l) : `<span class="leads-badge" data-s="${esc(l.status)}">${esc(l.status)}</span>`}</td>
      <td class="leads-muted" style="white-space:nowrap">${esc(when(l))}</td>
    </tr>`;
}

function filtered() {
  return state.filter === 'ALL' ? state.leads : state.leads.filter((l) => l.status === state.filter);
}

export function render() {
  ensureStyles();
  return `
    <div class="page-shell" data-section="leads">
      <div class="page-header">
        <div class="page-header-text">
          <h1 class="page-title">Leads</h1>
          <p class="page-description">People your magnets captured. Work them here or export to your CRM.</p>
        </div>
        <button class="btn btn-secondary" id="leads-export" type="button" style="display:none">
          <span class="material-symbols-outlined" aria-hidden="true">download</span>
          Export CSV
        </button>
      </div>
      <div class="dashboard-card">
        <div class="card-body" id="leads-body">
          ${emptyState('hourglass_empty', 'Loading leads…')}
        </div>
      </div>
    </div>`;
}

export async function init() {
  document.getElementById('leads-export')?.addEventListener('click', exportCsv);
  await load();
}

async function load() {
  const body = document.getElementById('leads-body');
  if (!body) return;
  try {
    const [lres, mres] = await Promise.all([
      fetch(`${apiBase()}/m5t/v5/m5mLead`),
      fetch(`${apiBase()}/m5t/v5/magnets`).catch(() => null),
    ]);
    const ldata = await lres.json().catch(() => ({}));
    if (!ldata.ok) throw new Error(ldata.message || 'Failed to load');
    state.leads = (ldata.data || []).filter((l) => !['DELETED', 'ARCHIVED'].includes(l.status));
    if (mres) {
      const mdata = await mres.json().catch(() => ({}));
      state.magnetNames = {};
      (mdata.magnets || []).forEach((m) => { state.magnetNames[m.guid] = m.name; });
      state.canManage = !!mdata.canManage;
    }
  } catch (err) {
    body.innerHTML = emptyState('error', 'Could not load your leads. Please try again.');
    return;
  }
  renderBody();
}

function renderBody() {
  const body = document.getElementById('leads-body');
  const exportBtn = document.getElementById('leads-export');
  if (!body) return;
  if (exportBtn) exportBtn.style.display = state.leads.length ? '' : 'none';

  if (!state.leads.length) {
    body.innerHTML = emptyState('inbox', 'No leads captured yet. Publish a magnet and share it to start collecting.');
    return;
  }

  const rows = filtered();
  body.innerHTML = `
    <div class="leads-bar">
      <div class="leads-filter">
        ${['ALL', ...STATUSES].map((s) => `<button data-filter="${s}" class="${state.filter === s ? 'active' : ''}">${s === 'ALL' ? 'All' : s[0] + s.slice(1).toLowerCase()}</button>`).join('')}
      </div>
      <span class="leads-count">${rows.length} of ${state.leads.length}</span>
    </div>
    <div class="leads-tablewrap">
      <table class="leads-table">
        <thead><tr><th>Name</th><th>Contact</th><th>Interest</th><th>Magnet</th><th>Status</th><th>Captured</th></tr></thead>
        <tbody id="leads-tbody">${rows.map(rowHTML).join('') || `<tr><td colspan="6"><div class="leads-muted" style="padding:14px 4px">No ${state.filter.toLowerCase()} leads.</div></td></tr>`}</tbody>
      </table>
    </div>`;

  body.querySelector('.leads-filter')?.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-filter]');
    if (!btn) return;
    state.filter = btn.dataset.filter;
    renderBody();
  });
  body.querySelector('#leads-tbody')?.addEventListener('change', onStatusChange);
  body.querySelector('#leads-tbody')?.addEventListener('click', (e) => {
    if (e.target.closest('.leads-status')) return; // the select handles itself
    const tr = e.target.closest('.leads-row');
    if (tr) openDrawer(tr.dataset.id);
  });
}

async function onStatusChange(e) {
  const sel = e.target.closest('.leads-status');
  if (!sel) return;
  const id = sel.dataset.id;
  const lead = state.leads.find((l) => String(l.id) === String(id));
  const next = sel.value;
  const prev = lead?.status;
  try {
    const res = await fetch(`${apiBase()}/m5t/v5/m5mLead/${encodeURIComponent(id)}`, {
      method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status: next }),
    });
    if (!(await res.json().catch(() => ({}))).ok) throw new Error();
    if (lead) lead.status = next;
    toast(`Marked ${next[0]}${next.slice(1).toLowerCase()}`, 'success');
    if (state.filter !== 'ALL') renderBody(); // may drop out of the current filter
  } catch {
    sel.value = prev || 'NEW';
    toast('Could not update status', 'danger');
  }
}

// ── detail drawer ────────────────────────────────────────────────────────────
function openDrawer(id) {
  const l = state.leads.find((x) => String(x.id) === String(id));
  if (!l) return;
  const magnet = state.magnetNames[l.magnet_guid] || l.lead_source || '—';
  const field = (k, v) => v ? `<div class="leads-drawer__field"><span class="leads-drawer__k">${esc(k)}</span><span class="leads-drawer__v">${esc(v)}</span></div>` : '';
  const scrim = document.createElement('div');
  scrim.className = 'leads-drawer-scrim';
  scrim.innerHTML = `
    <aside class="leads-drawer" role="dialog" aria-modal="true" aria-label="Lead detail">
      <div class="leads-drawer__head">
        <span class="leads-drawer__title">${esc(fullName(l))}</span>
        <button class="leads-drawer__close" type="button" aria-label="Close">&times;</button>
      </div>
      <div class="leads-drawer__body">
        <div class="leads-drawer__contact">
          ${l.email ? `<a class="leads-drawer__cbtn" href="mailto:${esc(l.email)}"><span class="material-symbols-outlined" aria-hidden="true">mail</span>Email</a>` : ''}
          ${l.phone ? `<a class="leads-drawer__cbtn" href="tel:${esc(String(l.phone).replace(/[^\d+]/g, ''))}"><span class="material-symbols-outlined" aria-hidden="true">call</span>Call</a>` : ''}
        </div>
        ${field('Status', l.status)}
        ${field('Email', l.email)}
        ${field('Phone', l.phone)}
        ${field('Mobile', l.mobile)}
        ${field('Company', l.company)}
        ${field('Title', l.title)}
        ${field('Interest', l.product_interest)}
        ${field('Location', [l.city, l.state].filter(Boolean).join(', '))}
        ${field('Channel', l.lead_source)}
        ${field('Magnet', magnet)}
        ${field('Captured', when(l))}
        ${field('Campaign', l.utm_campaign)}
        ${field('Ad source', [l.utm_source, l.utm_medium].filter(Boolean).join(' / '))}
        ${l.gclid ? `<div class="leads-drawer__field"><span class="leads-drawer__k">Paid click</span><span class="leads-drawer__v"><span class="leads-badge" data-s="QUALIFIED">Google Ads</span></span></div>` : ''}
        ${l.description ? `<div class="leads-drawer__notes">${esc(l.description)}</div>` : ''}
      </div>
    </aside>`;
  document.body.appendChild(scrim);
  requestAnimationFrame(() => { scrim.classList.add('open'); scrim.querySelector('.leads-drawer').classList.add('open'); });
  const close = () => { scrim.classList.remove('open'); setTimeout(() => scrim.remove(), 220); };
  scrim.querySelector('.leads-drawer__close').addEventListener('click', close);
  scrim.addEventListener('click', (e) => { if (e.target === scrim) close(); });
}

// ── CSV export (current filter) ──────────────────────────────────────────────
function exportCsv() {
  const rows = filtered();
  if (!rows.length) { toast('Nothing to export', 'info'); return; }
  const cols = ['first_name', 'last_name', 'email', 'phone', 'company', 'product_interest', 'lead_source', 'utm_source', 'utm_medium', 'utm_campaign', 'gclid', 'status'];
  const cell = (v) => `"${String(v ?? '').replace(/"/g, '""')}"`;
  const header = [...cols, 'magnet', 'captured'];
  const lines = [header.join(',')];
  for (const l of rows) {
    lines.push([...cols.map((c) => cell(l[c])), cell(state.magnetNames[l.magnet_guid] || l.lead_source || ''), cell(when(l))].join(','));
  }
  const blob = new Blob([lines.join('\n')], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `leads-${state.filter.toLowerCase()}.csv`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  toast(`Exported ${rows.length} lead${rows.length === 1 ? '' : 's'}`, 'success');
}
