/**
 * magnet-flow.js — the visual conversation flow builder for client-saas /magnets.
 *
 * A dedicated modal (opened from a magnet card's "Flow" button) that renders the magnet's
 * conversation as a vertical canvas of connected node-cards — one per step, type-colored,
 * showing a live preview of the prompt + choices. Cards drag-to-reorder (native HTML5 DnD
 * with drop indicators); click a card to expand it into an inline editor; add steps from a
 * type palette. Saves the whole flow via PATCH { steps } → mag_macro_steps.
 *
 * Linear model (matches the SDK): reorder / add / edit / delete. Any existing `goto` branch
 * on an option is preserved across a round-trip (free-form visual branching is future work).
 */

import AuthController from '../services/AuthController.js';
import PubSub from 'pubsub-js';
import AppBroadcast from '../../../../shared/appBroadcast.js';
import { openPreviewModal, magnetToPackage } from './magnet-preview.js';

const ESC = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };
const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ESC[c]);
const toast = (message, type = 'info') => { try { PubSub.publish(AppBroadcast.UI_TOAST, { message, type }); } catch { /* no-op */ } };
const apiBase = () => AuthController.getConfig?.().BASE_URL || '';

// step type → friendly label, node icon, accent color (value = SDK step_type)
const TYPE_META = {
  single_select: { label: 'Multiple choice', icon: 'quiz', color: '#0072BA' },
  multi_select: { label: 'Select all', icon: 'checklist', color: '#0E6BA8' },
  scheduler: { label: 'Scheduler', icon: 'event', color: '#915E8B' },
  text: { label: 'Short text', icon: 'short_text', color: '#5B54C6' },
  email: { label: 'Email', icon: 'mail', color: '#0E8F86' },
  phone: { label: 'Phone', icon: 'call', color: '#2E8B57' },
  message: { label: 'Message', icon: 'chat', color: '#B4791F' },
};
const TYPE_ORDER = ['single_select', 'multi_select', 'scheduler', 'text', 'email', 'phone', 'message'];
// Editable per-CTA routes (shown only when the magnet has that CTA). chat = mag_macro_steps.
const ROUTE_LABEL = { chat: 'Chat / default', book: 'Book (scheduler)', support: 'Support (intake)' };
const meta = (t) => TYPE_META[t] || TYPE_META.single_select;
const needsOptions = (v) => v === 'single_select' || v === 'multi_select';
const needsField = (v) => v !== 'message';
const needsSchedule = (v) => v === 'scheduler';
const defaultFieldFor = (v) => (v === 'email' ? 'email' : v === 'phone' ? 'phone' : v === 'scheduler' ? 'preferred_time' : '');
const defaultSchedule = () => ({ meeting_label: '', start: '09:00', end: '17:00', mins: 30, days: 14 });

const FIELD_SUGGESTIONS = ['first_name', 'last_name', 'email', 'phone', 'company', 'product_interest', 'budget', 'timeline', 'message'];
// icons the SDK can actually render (must match its MPATH registry); '' = none. Friendly labels.
const OPTION_ICONS = [
  ['', 'No icon'], ['event', 'Calendar'], ['schedule', 'Clock'], ['mail', 'Email'], ['sms', 'Text'],
  ['phone', 'Phone'], ['chat', 'Chat'], ['description', 'Document'], ['help', 'Question'], ['place', 'Location'],
  ['person', 'Person'], ['bolt', 'Quick'], ['check_circle', 'Check'], ['star', 'Star'], ['home', 'Home'], ['build', 'Service'],
];

function hexToRgba(hex, a) {
  const m = /^#?([0-9a-f]{2})([0-9a-f]{2})([0-9a-f]{2})$/i.exec(String(hex || '').trim());
  if (!m) return `rgba(0,114,186,${a})`;
  return `rgba(${parseInt(m[1], 16)},${parseInt(m[2], 16)},${parseInt(m[3], 16)},${a})`;
}

