// ── working state (one editor open at a time) ────────────────────────────────
let stepsModel = [];
let openUid = null;
let uidSeq = 0;
let dragUid = null;
let dropInfo = null;
const uid = () => 'f' + (++uidSeq);

function blankStep(type = 'single_select') {
  return {
    _uid: uid(),
    id: '', // assigned at save (stable numbering; preserves goto targets)
    step_type: type,
    step_prompts: [''],
    step_options: needsOptions(type) ? [{ label: '', goto: '', icon: '' }, { label: '', goto: '', icon: '' }] : [],
    step_columns: defaultFieldFor(type) ? [defaultFieldFor(type)] : [],
    step_description: '',
    step_config: needsSchedule(type) ? defaultSchedule() : null,
  };
}

// One raw step array → an editable model (adds _uid, normalizes shapes).
function modelFromSteps(src) {
  return (Array.isArray(src) ? src : []).map((s) => ({
    _uid: uid(),
    id: s.id != null ? String(s.id) : '',
    step_type: TYPE_META[s.step_type] ? s.step_type : 'single_select',
    step_prompts: Array.isArray(s.step_prompts) ? s.step_prompts.map(String) : [],
    step_options: (Array.isArray(s.step_options) ? s.step_options : []).map((o) => ({
      label: o && o.label != null ? String(o.label) : '',
      goto: o && o.goto != null ? String(o.goto) : '',
      icon: o && o.icon != null ? String(o.icon) : '',
    })),
    step_columns: Array.isArray(s.step_columns) ? s.step_columns.map(String) : [],
    step_description: s.step_description != null ? String(s.step_description) : '',
    step_config: (s.step_config && typeof s.step_config === 'object') ? { ...defaultSchedule(), ...s.step_config } : (s.step_type === 'scheduler' ? defaultSchedule() : null),
  }));
}

// The shared name→email capture tail the SDK appends to the built-in book/support routes.
function captureTailModel() {
  return [
    { _uid: uid(), id: '', step_type: 'text', step_prompts: ['Great — and your name?'], step_options: [], step_columns: ['first_name'], step_description: '', step_config: null },
    { _uid: uid(), id: '', step_type: 'email', step_prompts: ['The best email to reach you?'], step_options: [], step_columns: ['email'], step_description: '', step_config: null },
  ];
}

// Seed a book/support route the FIRST time it's opened, mirroring the SDK's built-in defaults
// (support options come from the magnet's Support CTA config when it has any).
function seedRouteModel(route, magnet) {
  if (route === 'book') {
    return [{ _uid: uid(), id: '', step_type: 'scheduler', step_prompts: ['When works best for you?'], step_options: [], step_columns: ['preferred_time'], step_description: '', step_config: defaultSchedule() }, ...captureTailModel()];
  }
  if (route === 'support') {
    const supp = (magnet.actions || []).find((a) => a && a.type === 'support');
    const cfgOpts = (supp && supp.config && Array.isArray(supp.config.options)) ? supp.config.options : [];
    const options = (cfgOpts.length ? cfgOpts.map((o) => ({ label: (o && o.label) || String(o), goto: '', icon: (o && o.icon) || '' }))
      : ['Sales enquiry', 'Support', 'Billing', 'Something else'].map((l) => ({ label: l, goto: '', icon: '' })));
    return [{ _uid: uid(), id: '', step_type: 'multi_select', step_prompts: ['How can we help you today?'], step_options: options, step_columns: ['support_topics'], step_description: 'Select all that apply', step_config: null }, ...captureTailModel()];
  }
  return [blankStep('single_select')];
}

// Build the working model for a route: authored steps if present, else the seed (book/support)
// or a blank first step (chat).
function loadRouteModel(route, magnet) {
  const authored = route === 'chat' ? magnet.steps : (magnet.routes && magnet.routes[route]);
  const model = modelFromSteps(authored);
  if (model.length) return model;
  return route === 'chat' ? [blankStep('single_select')] : seedRouteModel(route, magnet);
}

// keep options/field/config in sync with a step's type after a type change
function reconcileStep(step) {
  if (needsOptions(step.step_type)) {
    if (!step.step_options.length) step.step_options = [{ label: '', goto: '', icon: '' }, { label: '', goto: '', icon: '' }];
  } else {
    step.step_options = [];
  }
  if (needsField(step.step_type)) {
    if (!step.step_columns.length && defaultFieldFor(step.step_type)) step.step_columns = [defaultFieldFor(step.step_type)];
  } else {
    step.step_columns = [];
  }
  step.step_config = needsSchedule(step.step_type) ? (step.step_config || defaultSchedule()) : null;
}

// ── markup ───────────────────────────────────────────────────────────────────
function optionRowHTML(opt, only) {
  return `<div class="flow-opt">
    <input class="mag-modal__input flow-o-label" type="text" value="${esc(opt.label)}" placeholder="Option label">
    <select class="mag-modal__select flow-o-icon" title="Icon">${OPTION_ICONS.map(([v, l]) =>
      `<option value="${esc(v)}"${v === opt.icon ? ' selected' : ''}>${esc(l)}</option>`).join('')}</select>
    <button class="flow-opt__del" type="button" data-x="delopt" title="Remove choice"${only ? ' disabled' : ''}><span class="material-symbols-outlined" aria-hidden="true">close</span></button>
  </div>`;
}

function editorBodyHTML(step) {
  const typeOpts = TYPE_ORDER.map((t) => `<option value="${t}"${t === step.step_type ? ' selected' : ''}>${esc(meta(t).label)}</option>`).join('');
  const only = step.step_options.length <= 1;
  return `<div class="flow-node__body">
    <label class="mag-modal__label">Step type</label>
    <select class="mag-modal__select flow-f-type">${typeOpts}</select>

    <label class="mag-modal__label">${step.step_type === 'message' ? 'Message' : 'Question'} <span class="flow-sub">one bubble per line</span></label>
    <textarea class="mag-modal__input flow-f-prompts" rows="2" placeholder="${step.step_type === 'message' ? 'Thanks! One moment…' : 'What can we help you with?'}">${esc(step.step_prompts.join('\n'))}</textarea>

    ${needsField(step.step_type) ? `
    <label class="mag-modal__label">Saves to</label>
    <input class="mag-modal__input flow-f-field" type="text" list="flow-fields" value="${esc(step.step_columns[0] || '')}" placeholder="e.g. first_name">
    <p class="mag-modal__hint">The lead field this answer fills. Pick a suggestion or type your own.</p>` : ''}

    ${needsOptions(step.step_type) ? `
    <label class="mag-modal__label">Choices${step.step_type === 'multi_select' ? ' <span class="flow-sub">visitor can pick several</span>' : ''}</label>
    <div class="flow-opts">${step.step_options.map((o) => optionRowHTML(o, only)).join('')}</div>
    <button class="mag-flow__addopt" type="button" data-x="addopt"><span class="material-symbols-outlined" aria-hidden="true">add</span> Add choice</button>` : ''}

    ${needsSchedule(step.step_type) ? `
    <label class="mag-modal__label">Meeting label <span class="flow-sub">optional</span></label>
    <input class="mag-modal__input flow-f-mtlabel" type="text" value="${esc(step.step_config?.meeting_label || '')}" placeholder="e.g. 15 minute call">
    <div class="mag-modal__row" style="margin-top:8px">
      <div><label class="mag-modal__label">From</label><input class="mag-modal__input flow-f-start" type="time" value="${esc(step.step_config?.start || '09:00')}"></div>
      <div><label class="mag-modal__label">To</label><input class="mag-modal__input flow-f-end" type="time" value="${esc(step.step_config?.end || '17:00')}"></div>
      <div style="flex:0 0 auto"><label class="mag-modal__label">Slot</label>
        <select class="mag-modal__select flow-f-mins">${[15, 30, 45, 60].map((n) => `<option value="${n}"${(step.step_config?.mins || 30) === n ? ' selected' : ''}>${n} min</option>`).join('')}</select></div>
    </div>
    <p class="mag-modal__hint">Visitors pick a day + time within these hours; the choice saves to the field above.</p>` : ''}
  </div>`;
}

function previewHTML(step) {
  const firstPrompt = step.step_prompts.find((p) => String(p).trim() !== '') || '';
  const promptText = firstPrompt
    ? `<div class="flow-node__prompt">“${esc(firstPrompt)}”</div>`
    : `<div class="flow-node__prompt is-empty">${step.step_type === 'message' ? 'No message yet' : 'No question yet'}</div>`;
  let extra = '';
  if (needsOptions(step.step_type)) {
    const labels = step.step_options.map((o) => String(o.label).trim()).filter(Boolean);
    if (labels.length) {
      const shown = labels.slice(0, 4).map((l) => `<span class="flow-node__chip">${esc(l)}</span>`).join('');
      const more = labels.length > 4 ? `<span class="flow-node__chip">+${labels.length - 4}</span>` : '';
      extra = `<div class="flow-node__chips">${shown}${more}</div>`;
    }
  } else if (needsField(step.step_type) && step.step_columns[0]) {
    extra = `<div class="flow-node__meta">Saves to <b>${esc(step.step_columns[0])}</b></div>`;
  }
  return `<div class="flow-node__preview">${promptText}${extra}</div>`;
}

function nodeHTML(step, i, total) {
  const m = meta(step.step_type);
  const open = step._uid === openUid;
  const style = `--nc:${m.color};--nct:${hexToRgba(m.color, 0.14)}`;
  return `<div class="flow-node${open ? ' flow-node--open' : ''}" data-uid="${step._uid}" style="${style}"${open ? '' : ' draggable="true"'}>
    <div class="flow-node__hd">
      <span class="flow-node__grip" title="${open ? '' : 'Drag to reorder'}"><span class="material-symbols-outlined" aria-hidden="true">${open ? 'expand_less' : 'drag_indicator'}</span></span>
      <span class="flow-node__ico"><span class="material-symbols-outlined" aria-hidden="true">${m.icon}</span></span>
      <span class="flow-node__type">${esc(m.label)}</span>
      <span class="flow-node__n">Step ${i + 1}</span>
      <span class="flow-node__tools">
        <button type="button" data-x="up" title="Move up"${i === 0 ? ' disabled' : ''}><span class="material-symbols-outlined" aria-hidden="true">arrow_upward</span></button>
        <button type="button" data-x="down" title="Move down"${i === total - 1 ? ' disabled' : ''}><span class="material-symbols-outlined" aria-hidden="true">arrow_downward</span></button>
        <button type="button" data-x="del" title="Delete step"${total === 1 ? ' disabled' : ''}><span class="material-symbols-outlined" aria-hidden="true">delete</span></button>
      </span>
    </div>
    ${open ? editorBodyHTML(step) : previewHTML(step)}
  </div>`;
}

const CONNECTOR = `<div class="flow-conn"><span class="flow-conn__line"></span><span class="material-symbols-outlined" aria-hidden="true">expand_more</span></div>`;

function renderNodes() {
  const canvas = document.getElementById('flow-nodes');
  if (!canvas) return;
  const total = stepsModel.length;
  const parts = ['<div class="flow-start"><span class="material-symbols-outlined" aria-hidden="true">bolt</span> Conversation starts</div>', CONNECTOR];
  stepsModel.forEach((s, i) => {
    parts.push(nodeHTML(s, i, total));
    if (i < total - 1) parts.push(CONNECTOR);
  });
  canvas.innerHTML = parts.join('');
}

// Sync the currently-open node's live inputs back into the model (only the open card
// has editable fields; collapsed cards render from the model).
function readModel() {
  const el = document.querySelector('.flow-node--open');
  if (!el) return;
  const step = stepsModel.find((s) => s._uid === el.dataset.uid);
  if (!step) return;
  const typeEl = el.querySelector('.flow-f-type');
  if (typeEl) step.step_type = typeEl.value;
  const promptsEl = el.querySelector('.flow-f-prompts');
  if (promptsEl) step.step_prompts = promptsEl.value.split('\n');
  const fieldEl = el.querySelector('.flow-f-field');
  step.step_columns = fieldEl && fieldEl.value.trim() ? [fieldEl.value.trim()] : [];
  if (needsOptions(step.step_type)) {
    const prev = step.step_options;
    const newOpts = [];
    el.querySelectorAll('.flow-opt').forEach((oEl, k) => {
      newOpts.push({
        label: oEl.querySelector('.flow-o-label')?.value ?? '',
        icon: oEl.querySelector('.flow-o-icon')?.value ?? '',
        goto: (prev[k] && prev[k].goto) || '', // preserve any existing branch by position
      });
    });
    step.step_options = newOpts;
  } else {
    step.step_options = [];
  }
  if (needsSchedule(step.step_type)) {
    const mt = el.querySelector('.flow-f-mtlabel');
    const st = el.querySelector('.flow-f-start');
    const en = el.querySelector('.flow-f-end');
    const mn = el.querySelector('.flow-f-mins');
    step.step_config = {
      ...(step.step_config || defaultSchedule()),
      ...(mt ? { meeting_label: mt.value.trim() } : {}),
      ...(st && st.value ? { start: st.value } : {}),
      ...(en && en.value ? { end: en.value } : {}),
      ...(mn ? { mins: parseInt(mn.value, 10) || 30 } : {}),
    };
  } else {
    step.step_config = null;
  }
}

function clearDrop() {
  document.querySelectorAll('.flow-node.drop-before, .flow-node.drop-after')
    .forEach((n) => n.classList.remove('drop-before', 'drop-after'));
}
function cleanupDrag() {
  clearDrop();
  document.querySelectorAll('.flow-node.dragging').forEach((n) => n.classList.remove('dragging'));
  dragUid = null;
  dropInfo = null;
}

function validate(model = stepsModel) {
  if (!model.length) return 'Add at least one step.';
  for (let i = 0; i < model.length; i++) {
    const s = model[i];
    const n = i + 1;
    if (!s.step_prompts.some((p) => String(p).trim() !== '')) return `Step ${n}: add what the magnet should say.`;
    if (needsOptions(s.step_type) && !s.step_options.some((o) => String(o.label).trim() !== '')) return `Step ${n}: add at least one choice.`;
    if (needsField(s.step_type) && !s.step_columns.length) return `Step ${n}: choose which field this answer saves to.`;
  }
  return '';
}

function toPayload(model = stepsModel) {
  let max = 0;
  model.forEach((s) => { const n = parseInt(s.id, 10); if (!isNaN(n) && n > max) max = n; });
  return model.map((s) => {
    const id = s.id && String(s.id).trim() ? String(s.id) : String(++max);
    const options = needsOptions(s.step_type)
      ? s.step_options.map((o) => {
          const out = { label: String(o.label).trim(), goto: String(o.goto || '') };
          if (o.icon) out.icon = String(o.icon);
          return out;
        }).filter((o) => o.label !== '')
      : [];
    const out = {
      id,
      step_type: s.step_type,
      step_prompts: s.step_prompts.map((p) => String(p)).filter((p) => p.trim() !== ''),
      step_options: options,
      step_columns: s.step_columns.slice(),
      step_description: s.step_description || '',
    };
    if (needsSchedule(s.step_type) && s.step_config) out.step_config = { ...defaultSchedule(), ...s.step_config };
    return out;
  });
}

// ── open ─────────────────────────────────────────────────────────────────────
export function openFlowModal(magnet, onSaved) {
  ensureStyles();
  // Editable routes: the chat/default flow, plus book/support when the magnet has those CTAs.
  const routeKeys = ['chat', ...['book', 'support'].filter((r) => (magnet.actions || []).some((a) => a && a.type === r))];
  const routeModels = { chat: loadRouteModel('chat', magnet) };
  let currentRoute = 'chat';
  stepsModel = routeModels.chat;
  openUid = stepsModel.length === 1 ? stepsModel[0]._uid : null; // one step ⇒ start expanded
  dragUid = null;
  dropInfo = null;

  const scrim = document.createElement('div');
  scrim.className = 'mag-modal-scrim';
  scrim.innerHTML = `
    <div class="mag-modal mag-flow" role="dialog" aria-modal="true" aria-label="Flow builder">
      <div class="mag-modal__head">
        <span class="mag-modal__title">Flow builder — ${esc(magnet.name || 'magnet')}</span>
        <button class="mag-modal__close" type="button" aria-label="Close">&times;</button>
      </div>
      <div class="mag-modal__body">
        <p class="mag-modal__hint" style="margin-top:0">Each card is one thing your magnet asks. Drag a card to reorder, click to edit, add steps from the palette below.</p>
        ${routeKeys.length > 1 ? `<div class="flow-routes"><span class="flow-routes__lbl">Editing flow</span><select class="mag-modal__select" id="flow-route">${routeKeys.map((r) => `<option value="${r}">${esc(ROUTE_LABEL[r] || r)}</option>`).join('')}</select></div>` : ''}
        <datalist id="flow-fields">${FIELD_SUGGESTIONS.map((f) => `<option value="${esc(f)}"></option>`).join('')}</datalist>
        <div class="flow-canvas" id="flow-nodes"></div>
        <div class="flow-palette">
          <p class="flow-palette__t">Add a step</p>
          <div class="flow-palette__grid" id="flow-palette">
            ${TYPE_ORDER.map((t) => { const m = meta(t); return `<button class="flow-palette__chip" type="button" data-type="${t}" style="--pc:${m.color}"><span class="material-symbols-outlined" aria-hidden="true">${m.icon}</span>${esc(m.label)}</button>`; }).join('')}
          </div>
        </div>
        <p class="mag-modal__error" id="flow-error"></p>
        <div class="mag-modal__actions">
          <button class="mag-modal__btn mag-modal__btn--ghost" type="button" data-x="preview" style="margin-right:auto"><span class="material-symbols-outlined" aria-hidden="true" style="font-size:18px;vertical-align:-4px;margin-right:4px">visibility</span>Preview</button>
          <button class="mag-modal__btn mag-modal__btn--ghost" type="button" data-x="cancel">Cancel</button>
          <button class="mag-modal__btn mag-modal__btn--primary" type="button" data-x="save">Save flow</button>
        </div>
      </div>
    </div>`;
  document.body.appendChild(scrim);
  renderNodes();
  requestAnimationFrame(() => { scrim.classList.add('open'); scrim.querySelector('.mag-modal').classList.add('open'); });

  const errEl = scrim.querySelector('#flow-error');
  const canvas = scrim.querySelector('#flow-nodes');
  const clearErr = () => { errEl.textContent = ''; };

  const close = () => { cleanupDrag(); scrim.classList.remove('open'); setTimeout(() => scrim.remove(), 180); };
  scrim.querySelector('.mag-modal__close').addEventListener('click', close);
  scrim.querySelector('[data-x="cancel"]').addEventListener('click', close);
  scrim.addEventListener('click', (e) => { if (e.target === scrim) close(); });

  // Preview the route being edited (unsaved) as a straight flow — home off so it opens into it.
  scrim.querySelector('[data-x="preview"]').addEventListener('click', () => {
    readModel();
    openPreviewModal(() => magnetToPackage({ ...magnet, home: false, steps: toPayload(routeModels[currentRoute]) }));
  });

  // Switch which CTA route we're editing — stash the current model, load/seed the target.
  const routeSel = scrim.querySelector('#flow-route');
  routeSel?.addEventListener('change', () => {
    readModel(); // stepsModel is the current route's model by reference — sync the open card into it
    currentRoute = routeSel.value;
    if (!routeModels[currentRoute]) routeModels[currentRoute] = loadRouteModel(currentRoute, magnet);
    stepsModel = routeModels[currentRoute];
    openUid = stepsModel.length === 1 ? stepsModel[0]._uid : null;
    clearErr();
    renderNodes();
  });

  const openStep = (targetUid) => { clearErr(); readModel(); openUid = openUid === targetUid ? null : targetUid; renderNodes(); };

  // clicks: tools, expand/collapse, add/remove choice
  canvas.addEventListener('click', (e) => {
    const toolBtn = e.target.closest('button[data-x]');
    const nodeEl = e.target.closest('.flow-node');
    if (!nodeEl) return;
    const i = stepsModel.findIndex((s) => s._uid === nodeEl.dataset.uid);
    if (i < 0) return;

    if (toolBtn) {
      const x = toolBtn.dataset.x;
      clearErr();
      readModel();
      if (x === 'up' && i > 0) { [stepsModel[i - 1], stepsModel[i]] = [stepsModel[i], stepsModel[i - 1]]; renderNodes(); }
      else if (x === 'down' && i < stepsModel.length - 1) { [stepsModel[i + 1], stepsModel[i]] = [stepsModel[i], stepsModel[i + 1]]; renderNodes(); }
      else if (x === 'del' && stepsModel.length > 1) { if (openUid === nodeEl.dataset.uid) openUid = null; stepsModel.splice(i, 1); renderNodes(); }
      else if (x === 'addopt') { stepsModel[i].step_options.push({ label: '', goto: '', icon: '' }); renderNodes(); }
      else if (x === 'delopt') {
        const optEl = toolBtn.closest('.flow-opt');
        const k = Array.from(optEl.parentNode.children).indexOf(optEl);
        if (stepsModel[i].step_options.length > 1 && k >= 0) { stepsModel[i].step_options.splice(k, 1); renderNodes(); }
      }
      return;
    }
    // a click on the header or the preview (not inside the editor body) toggles the card
    if (e.target.closest('.flow-node__body')) return;
    if (e.target.closest('.flow-node__hd') || e.target.closest('.flow-node__preview')) openStep(nodeEl.dataset.uid);
  });

  // type change inside the open editor → resync, reconcile, re-render (stay open)
  canvas.addEventListener('change', (e) => {
    if (!e.target.classList.contains('flow-f-type')) return;
    clearErr();
    readModel();
    const step = stepsModel.find((s) => s._uid === e.target.closest('.flow-node')?.dataset.uid);
    if (step) reconcileStep(step);
    renderNodes();
  });

  // ── native drag-to-reorder ──
  canvas.addEventListener('dragstart', (e) => {
    const node = e.target.closest('.flow-node');
    if (!node || node.getAttribute('draggable') !== 'true') return;
    dragUid = node.dataset.uid;
    e.dataTransfer.effectAllowed = 'move';
    try { e.dataTransfer.setData('text/plain', dragUid); } catch { /* some browsers require a payload */ }
    requestAnimationFrame(() => node.classList.add('dragging'));
  });
  canvas.addEventListener('dragover', (e) => {
    if (!dragUid) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    const node = e.target.closest('.flow-node');
    clearDrop();
    if (!node || node.dataset.uid === dragUid) { dropInfo = null; return; }
    const r = node.getBoundingClientRect();
    const after = e.clientY > r.top + r.height / 2;
    node.classList.add(after ? 'drop-after' : 'drop-before');
    dropInfo = { uid: node.dataset.uid, after };
  });
  canvas.addEventListener('drop', (e) => {
    if (!dragUid || !dropInfo) { cleanupDrag(); return; }
    e.preventDefault();
    clearErr();
    readModel();
    const from = stepsModel.findIndex((s) => s._uid === dragUid);
    if (from < 0) { cleanupDrag(); return; }
    const [moved] = stepsModel.splice(from, 1);
    const to = stepsModel.findIndex((s) => s._uid === dropInfo.uid);
    if (to < 0) { stepsModel.splice(from, 0, moved); cleanupDrag(); return; }
    stepsModel.splice(dropInfo.after ? to + 1 : to, 0, moved);
    cleanupDrag();
    renderNodes();
  });
  canvas.addEventListener('dragend', cleanupDrag);

  // palette → append a step of the chosen type, expanded for editing
  scrim.querySelector('#flow-palette').addEventListener('click', (e) => {
    const chip = e.target.closest('[data-type]');
    if (!chip) return;
    clearErr();
    readModel();
    const step = blankStep(chip.dataset.type);
    stepsModel.push(step);
    openUid = step._uid;
    renderNodes();
    canvas.lastElementChild?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  });

  scrim.querySelector('[data-x="save"]').addEventListener('click', async (ev) => {
    const saveBtn = ev.currentTarget;
    readModel();
    // Validate every route we've opened; on failure, jump to that route so the error is in context.
    const loaded = Object.keys(routeModels);
    for (const r of loaded) {
      const problem = validate(routeModels[r]);
      if (problem) {
        if (r !== currentRoute) {
          currentRoute = r;
          stepsModel = routeModels[r];
          openUid = null;
          if (routeSel) routeSel.value = r;
          renderNodes();
        }
        errEl.textContent = (loaded.length > 1 ? `${ROUTE_LABEL[r] || r}: ` : '') + problem;
        return;
      }
    }
    saveBtn.disabled = true;
    errEl.textContent = '';
    try {
      // One PATCH per opened route: chat → mag_macro_steps; book/support → mag_routes.<route>.
      for (const r of loaded) {
        const body = r === 'chat' ? { steps: toPayload(routeModels[r]) } : { route: r, steps: toPayload(routeModels[r]) };
        const res = await fetch(`${apiBase()}/m5t/v5/magnets/${encodeURIComponent(magnet.guid)}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body),
        });
        const data = await res.json().catch(() => ({}));
        if (!data.ok) throw new Error(data.message || 'Save failed');
      }
      toast(loaded.length > 1 ? 'Flows saved' : 'Flow saved', 'success');
      close();
      if (typeof onSaved === 'function') onSaved();
    } catch (err) {
      saveBtn.disabled = false;
      errEl.textContent = err.message || 'Something went wrong.';
    }
  });
}

export default { openFlowModal };
