/**
 * magnets-route.js — client-saas /magnets
 *
 * Self-serve magnet lifecycle. Lists the caller's magnets (an app + its conversation), and —
 * for owner/admin/member of a reseller or self-serve org (PROVISION_MAGNETS) — create / edit
 * basics / enable-disable / delete, and copy the embed snippet. Managed clients + viewers see
 * a read-only list (the server enforces the same gates).
 *   GET    /m5t/v5/magnets        POST /m5t/v5/magnets
 *   PATCH  /m5t/v5/magnets/:guid  DELETE /m5t/v5/magnets/:guid
 */

import AuthController from '../services/AuthController.js';
import PubSub from 'pubsub-js';
import AppBroadcast from '../../../../shared/appBroadcast.js';
import { openFlowModal } from './magnet-flow.js';
import { openPreviewModal, magnetToPackage } from './magnet-preview.js';

let stylesInjected = false;
const state = { magnets: [], owners: [], canProvision: false, canManage: false, primaryOrgGuid: null };

const ESC = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };
const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ESC[c]);
const toast = (message, type = 'info') => { try { PubSub.publish(AppBroadcast.UI_TOAST, { message, type }); } catch { /* no-op */ } };
const apiBase = () => AuthController.getConfig?.().BASE_URL || '';
const embedFor = (guid) => `<script src="${apiBase()}/m5t/v5/coreSnippet?appguid=${guid}" async></` + `script>`;

// ── configurator vocab (mirrors the SDK + API contract) ──────────────────────
const MODE_LABEL = { chat: 'Chat bubble', right_slide: 'Slide-in panel', modal: 'Modal', inline: 'Inline' };
const MODE_ICON = { chat: 'chat', right_slide: 'vertical_split', modal: 'web_asset', inline: 'view_agenda' };
const DISPLAY_OPTS = [
  { value: 'inline', icon: 'view_agenda', label: 'Inline' },
  { value: 'chat', icon: 'chat', label: 'Chat' },
  { value: 'right_slide', icon: 'vertical_split', label: 'Slide' },
  { value: 'modal', icon: 'web_asset', label: 'Modal' },
];
const THEME_OPTS = [
  { value: 'auto', icon: 'brightness_auto', label: 'Auto' },
  { value: 'light', icon: 'light_mode', label: 'Light' },
  { value: 'dark', icon: 'dark_mode', label: 'Dark' },
];
// Hub CTA bar. `kind` drives the row UI + how the action is collected:
//   value  → a contact input (call/email)   book → scheduler, optional label/booking-link
//   flow   → routes to the guided flow (chat)  support → multi-select intake (+ options list)
const CTA_META = {
  book: { label: 'Book', icon: 'event', kind: 'book' },
  chat: { label: 'Chat', icon: 'chat', kind: 'flow' },
  call: { label: 'Call', icon: 'phone', kind: 'value', placeholder: 'Phone number' },
  email: { label: 'Email', icon: 'mail', kind: 'value', placeholder: 'Email address' },
  support: { label: 'Support', icon: 'support_agent', kind: 'support' },
};
const CTA_ORDER = ['book', 'chat', 'call', 'email', 'support'];

// A radio-chip segmented control (accessible; value read via :checked).
function segHTML(name, current, opts) {
  return `<div class="mag-seg" role="radiogroup" aria-label="${esc(name)}">${opts.map((o) => `
    <label><input type="radio" name="${esc(name)}" value="${esc(o.value)}"${o.value === current ? ' checked' : ''}>
      <span><span class="material-symbols-outlined" aria-hidden="true">${esc(o.icon)}</span>${esc(o.label)}</span></label>`).join('')}</div>`;
}

// One opt-in CTA row (kind-aware): toggle + the right control. Prefilled from the saved action.
function ctaRowHTML(type, action) {
  const meta = CTA_META[type];
  const on = !!action;
  const dis = on ? '' : ' disabled';
  let control = '';
  if (meta.kind === 'value') {
    control = `<input class="mag-modal__input mag-cta__val" type="text" placeholder="${esc(meta.placeholder)}" value="${esc(action?.value || '')}"${dis}>`;
  } else if (meta.kind === 'book') {
    const bookVal = action?.config?.meeting_label || action?.value || '';
    control = `<input class="mag-modal__input mag-cta__val" type="text" placeholder="Meeting label (e.g. 15 minute call) — or paste a booking link" value="${esc(bookVal)}"${dis}>`;
  } else {
    control = `<span class="mag-cta__note">${meta.kind === 'support' ? 'Multi-select intake' : 'Opens your conversation flow'}</span>`;
  }
  let sub = '';
  if (meta.kind === 'support') {
    const opts = (action?.config?.options || []).map((o) => (o && o.label) || o).filter(Boolean);
    sub = `<textarea class="mag-modal__input mag-cta__opts" rows="3" placeholder="Support options — one per line (e.g. Sales&#10;Support&#10;Billing)"${dis}>${esc(opts.join('\n'))}</textarea>`;
  }
  return `<div class="mag-cta" data-type="${type}" data-kind="${meta.kind}">
    <div class="mag-cta__main">
      <label class="mag-cta__tog"><input type="checkbox" class="mag-cta__on"${on ? ' checked' : ''}>
        <span class="material-symbols-outlined" aria-hidden="true">${meta.icon}</span>${meta.label}</label>
      ${control}
    </div>
    ${sub}
  </div>`;
}

